Data Acquisition

State Population via tidycensus


Code
library(tidyverse)
library(tidycensus)
library(readxl)
library(gt)

data_dir &lt;- file.path("data", "mp03")
if (!dir.exists(data_dir)) dir.create(data_dir, recursive = TRUE)

years &lt;- c(2015:2019, 2021:2024)

state_pop &lt;- map_dfr(years, function(yr) {
  get_acs(
    variables   = c(total_population = "B01003_001"),
    geography   = "state",
    year        = yr,
    survey      = "acs1",
    geometry    = FALSE,
    cache_table = TRUE
  ) |&gt;
    mutate(year = yr) |&gt;
    select(state_name = NAME, total_population = estimate, year)
})




State-to-State Migration Flows


Code
parse_migration_table &lt;- function(file_path, year_current, year_1y) {
  raw         &lt;- read_excel(file_path, sheet = "Table", col_names = FALSE)
  header_row  &lt;- as.character(raw[7, ])
  state_cols  &lt;- seq(10, ncol(raw), by = 2)
  state_names &lt;- header_row[state_cols]
  state_names &lt;- state_names[state_names %in% state.name]
  state_cols  &lt;- state_cols[header_row[state_cols] %in% state.name]

  data &lt;- read_excel(file_path, sheet = "Table", skip = 8, col_names = FALSE) |&gt;
    filter(!is.na(...1),
           !str_starts(...1, "United States"),
           !str_starts(...1, "Puerto Rico"))

  stationary &lt;- data |&gt;
    select(state_current = 1, population = 4) |&gt;
    mutate(
      state_current = str_remove(state_current, "\\d+$") |&gt; str_trim(),
      state_1y      = state_current,
      population    = as.integer(str_remove_all(population, ",")),
      year_current  = year_current,
      year_1y       = year_1y
    ) |&gt;
    filter(state_current %in% state.name) |&gt;
    select(state_current, state_1y, population, year_current, year_1y)

  flows &lt;- map2_dfr(state_cols, state_names, function(col_idx, origin) {
    data |&gt;
      select(state_current = 1, population = all_of(col_idx)) |&gt;
      mutate(
        state_current = str_remove(state_current, "\\d+$") |&gt; str_trim(),
        state_1y      = origin,
        population    = case_when(
          population == "N" ~ 0L,
          population == "X" ~ NA_integer_,
          TRUE ~ as.integer(str_remove_all(population, ","))
        ),
        year_current  = year_current,
        year_1y       = year_1y
      ) |&gt;
      filter(!is.na(population), state_current %in% state.name,
             state_current != state_1y) |&gt;
      select(state_current, state_1y, population, year_current, year_1y)
  })

  bind_rows(stationary, flows)
}

get_flow_file &lt;- function(url, filename, year_current, year_1y) {
  fp &lt;- file.path(data_dir, filename)
  if (!file.exists(fp)) download.file(url, destfile = fp, mode = "wb", quiet = TRUE)
  parse_migration_table(fp, year_current, year_1y)
}

flows_2024 &lt;- get_flow_file(
  paste0("https://www2.census.gov/programs-surveys/demo/tables/",
